  1вҶ’import { NextRequest, NextResponse } from "next/server";
  2вҶ’import prisma from "@/lib/db";
  3вҶ’import { getAuthenticatedUserId, unauthorizedResponse } from "@/lib/auth-utils";
  4вҶ’import {
  5вҶ’  isCarryoverTransaction,
  6вҶ’  findMatchingBillPayment,
  7вҶ’  calculateInterest,
  8вҶ’} from "@/lib/carryover-detector";
  9вҶ’
 10вҶ’// Normalize text for matching (lowercase, remove accents)
 11вҶ’function normalizeText(text: string): string {
 12вҶ’  return text
 13вҶ’    .toLowerCase()
 14вҶ’    .normalize("NFD")
 15вҶ’    .replace(/[\u0300-\u036f]/g, "")
 16вҶ’    .trim();
 17вҶ’}
 18вҶ’
 19вҶ’// Check if transaction description matches recurring expense keywords
 20вҶ’function matchesRecurring(
 21вҶ’  transactionDesc: string,
 22вҶ’  recurringDesc: string
 23вҶ’): boolean {
 24вҶ’  const normalizedTransaction = normalizeText(transactionDesc);
 25вҶ’  const normalizedRecurring = normalizeText(recurringDesc);
 26вҶ’
 27вҶ’  // Split recurring description into keywords
 28вҶ’  const keywords = normalizedRecurring.split(/\s+/).filter((k) => k.length > 2);
 29вҶ’
 30вҶ’  // Check if any keyword is contained in the transaction description
 31вҶ’  return keywords.some((keyword) => normalizedTransaction.includes(keyword));
 32вҶ’}
 33вҶ’
 34вҶ’export async function DELETE(request: NextRequest) {
 35вҶ’  try {
 36вҶ’    const userId = await getAuthenticatedUserId();
 37вҶ’    const searchParams = request.nextUrl.searchParams;
 38вҶ’    const batchId = searchParams.get("batchId");
 39вҶ’
 40вҶ’    if (!batchId) {
 41вҶ’      return NextResponse.json(
 42вҶ’        { error: "ID do lote e obrigatorio" },
 43вҶ’        { status: 400 }
 44вҶ’      );
 45вҶ’    }
 46вҶ’
 47вҶ’    // Soft delete all transactions from this import batch
 48вҶ’    const result = await prisma.transaction.updateMany({
 49вҶ’      where: {
 50вҶ’        userId,
 51вҶ’        importBatchId: batchId,
 52вҶ’        deletedAt: null,
 53вҶ’      },
 54вҶ’      data: {
 55вҶ’        deletedAt: new Date(),
 56вҶ’      },
 57вҶ’    });
 58вҶ’
 59вҶ’    if (result.count === 0) {
 60вҶ’      return NextResponse.json(
 61вҶ’        { error: "Nenhuma transacao encontrada para este lote" },
 62вҶ’        { status: 404 }
 63вҶ’      );
 64вҶ’    }
 65вҶ’
 66вҶ’    return NextResponse.json({
 67вҶ’      message: `${result.count} transacoes removidas`,
 68вҶ’      count: result.count,
 69вҶ’    });
 70вҶ’  } catch (error) {
 71вҶ’    if (error instanceof Error && error.message === "Unauthorized") {
 72вҶ’      return unauthorizedResponse();
 73вҶ’    }
 74вҶ’    console.error("Error deleting import batch:", error);
 75вҶ’    return NextResponse.json(
 76вҶ’      { error: "Erro ao remover importacao" },
 77вҶ’      { status: 500 }
 78вҶ’    );
 79вҶ’  }
 80вҶ’}
 81вҶ’
 82вҶ’export async function POST(request: NextRequest) {
 83вҶ’  try {
 84вҶ’    const userId = await getAuthenticatedUserId();
 85вҶ’    const body = await request.json();
 86вҶ’    const { transactions, origin } = body;
 87вҶ’
 88вҶ’    if (!transactions || !Array.isArray(transactions)) {
 89вҶ’      return NextResponse.json(
 90вҶ’        { error: "Transacoes invalidas" },
 91вҶ’        { status: 400 }
 92вҶ’      );
 93вҶ’    }
 94вҶ’
 95вҶ’    // Fetch ALL active recurring expenses for matching (not just autoGenerate=false)
 96вҶ’    const recurringToMatch = await prisma.recurringExpense.findMany({
 97вҶ’      where: {
 98вҶ’        userId,
 99вҶ’        isActive: true,
100вҶ’      },
101вҶ’      include: {
102вҶ’        transactions: {
103вҶ’          select: { id: true, date: true },
104вҶ’          where: { deletedAt: null },
105вҶ’        },
106вҶ’      },
107вҶ’    });
108вҶ’
109вҶ’    // Fetch user's category tags for validation
110вҶ’    const userTagIds = new Set(
111вҶ’      (await prisma.categoryTag.findMany({
112вҶ’        where: { userId },
113вҶ’        select: { id: true, categoryId: true },
114вҶ’      })).map(t => `${t.id}:${t.categoryId}`)
115вҶ’    );
116вҶ’
117вҶ’    // Generate a batch ID for this import
118вҶ’    const importBatchId = crypto.randomUUID();
119вҶ’
120вҶ’    const created = [];
121вҶ’    let linkedCount = 0;
122вҶ’    let carryoverLinkedCount = 0;
123вҶ’    const linkedCarryovers: Array<{
124вҶ’      transactionId: string;
125вҶ’      billPaymentId: string;
126вҶ’      fromBill: string;
127вҶ’      interestRate: number | null;
128вҶ’      interestAmount: number | null;
129вҶ’    }> = [];
130вҶ’
131вҶ’    for (const t of transactions) {
132вҶ’      // Determine type and amount sign
133вҶ’      const type = t.type || "EXPENSE";
134вҶ’      let amount = t.amount;
135вҶ’
136вҶ’      // Ensure amount sign matches type
137вҶ’      if (type === "EXPENSE" && amount > 0) {
138вҶ’        amount = -amount;
139вҶ’      } else if (type === "INCOME" && amount < 0) {
140вҶ’        amount = Math.abs(amount);
141вҶ’      }
142вҶ’
143вҶ’      // Parse date safely to avoid timezone issues with YYYY-MM-DD format
144вҶ’      const dateStr = typeof t.date === 'string' && !t.date.includes('T')
145вҶ’        ? t.date + 'T12:00:00'
146вҶ’        : t.date;
147вҶ’      const transactionDate = new Date(dateStr);
148вҶ’      const transactionMonth = transactionDate.getMonth();
149вҶ’      const transactionYear = transactionDate.getFullYear();
150вҶ’      const transactionOrigin = origin || t.origin || "Importacao CSV";
151вҶ’
152вҶ’      // Try to match with a recurring expense
153вҶ’      let matchedRecurringId: string | null = null;
154вҶ’
155вҶ’      // Validate frontend-provided recurringExpenseId belongs to this user
156вҶ’      if (t.recurringExpenseId) {
157вҶ’        const isOwned = recurringToMatch.some(r => r.id === t.recurringExpenseId);
158вҶ’        if (isOwned) {
159вҶ’          matchedRecurringId = t.recurringExpenseId;
160вҶ’        }
161вҶ’      }
162вҶ’
163вҶ’      // Only do server-side matching if no valid match from frontend
164вҶ’      if (!matchedRecurringId) {
165вҶ’        const matches = recurringToMatch.filter((recurring) => {
166вҶ’          // Check origin match
167вҶ’          if (recurring.origin !== transactionOrigin) {
168вҶ’            return false;
169вҶ’          }
170вҶ’
171вҶ’          // Check category match (if recurring has category defined)
172вҶ’          if (recurring.categoryId && t.categoryId && recurring.categoryId !== t.categoryId) {
173вҶ’            return false;
174вҶ’          }
175вҶ’
176вҶ’          // Check description match
177вҶ’          if (!matchesRecurring(t.description, recurring.description)) {
178вҶ’            return false;
179вҶ’          }
180вҶ’
181вҶ’          // Check if already has transaction for this month
182вҶ’          const hasThisMonth = recurring.transactions.some((existingTx) => {
183вҶ’            const existingDate = new Date(existingTx.date);
184вҶ’            return (
185вҶ’              existingDate.getMonth() === transactionMonth &&
186вҶ’              existingDate.getFullYear() === transactionYear
187вҶ’            );
188вҶ’          });
189вҶ’
190вҶ’          if (hasThisMonth) {
191вҶ’            return false;
192вҶ’          }
193вҶ’
194вҶ’          return true;
195вҶ’        });
196вҶ’
197вҶ’        // Only link if we have exactly one match (conservative)
198вҶ’        if (matches.length === 1) {
199вҶ’          matchedRecurringId = matches[0].id;
200вҶ’          // Add to existing transactions to prevent double matching in same import
201вҶ’          matches[0].transactions.push({ id: "temp", date: transactionDate });
202вҶ’          linkedCount++;
203вҶ’        }
204вҶ’      } else {
205вҶ’        linkedCount++;
206вҶ’      }
207вҶ’
208вҶ’      // Validate frontend-provided categoryTagId belongs to user and matches category
209вҶ’      let validatedTagId: string | null = null;
210вҶ’      if (t.categoryTagId) {
211вҶ’        const tagKey = `${t.categoryTagId}:${t.categoryId || ""}`;
212вҶ’        if (userTagIds.has(tagKey)) {
213вҶ’          validatedTagId = t.categoryTagId;
214вҶ’        }
215вҶ’      }
216вҶ’
217вҶ’      const transaction = await prisma.transaction.create({
218вҶ’        data: {
219вҶ’          userId,
220вҶ’          description: t.description,
221вҶ’          amount,
222вҶ’          date: transactionDate,
223вҶ’          type,
224вҶ’          origin: transactionOrigin,
225вҶ’          categoryId: t.categoryId || null,
226вҶ’          categoryTagId: validatedTagId,
227вҶ’          isFixed: matchedRecurringId !== null,
228вҶ’          isInstallment: t.isInstallment || false,
229вҶ’          currentInstallment: t.currentInstallment || null,
230вҶ’          totalInstallments: t.totalInstallments || null,
231вҶ’          recurringExpenseId: matchedRecurringId,
232вҶ’          importBatchId,
233вҶ’        },
234вҶ’        include: {
235вҶ’          category: true,
236вҶ’          recurringExpense: true,
237вҶ’        },
238вҶ’      });
239вҶ’      created.push(transaction);
240вҶ’
241вҶ’      // Check if this is a carryover transaction and try to link it to a BillPayment
242вҶ’      if (isCarryoverTransaction(t.description)) {
243вҶ’        try {
244вҶ’          const matchingBillPayment = await findMatchingBillPayment({
245вҶ’            origin: transactionOrigin,
246вҶ’            month: transactionMonth + 1, // Convert from 0-indexed to 1-indexed
247вҶ’            year: transactionYear,
248вҶ’            amount: Math.abs(amount),
249вҶ’            userId,
250вҶ’          });
251вҶ’
252вҶ’          if (matchingBillPayment) {
253вҶ’            // Calculate interest from the difference
254вҶ’            const interest = calculateInterest(
255вҶ’              matchingBillPayment.amountCarried,
256вҶ’              Math.abs(amount)
257вҶ’            );
258вҶ’
259вҶ’            // Update the BillPayment with the linked transaction and interest info
260вҶ’            await prisma.billPayment.update({
261вҶ’              where: { id: matchingBillPayment.id },
262вҶ’              data: {
263вҶ’                linkedTransactionId: transaction.id,
264вҶ’                interestRate: interest.rate,
265вҶ’                interestAmount: interest.amount,
266вҶ’              },
267вҶ’            });
268вҶ’
269вҶ’            // Soft delete the old carryover transaction if it exists
270вҶ’            if (matchingBillPayment.carryoverTransactionId) {
271вҶ’              await prisma.transaction.update({
272вҶ’                where: { id: matchingBillPayment.carryoverTransactionId },
273вҶ’                data: { deletedAt: new Date() },
274вҶ’              });
275вҶ’            }
276вҶ’
277вҶ’            carryoverLinkedCount++;
278вҶ’            linkedCarryovers.push({
279вҶ’              transactionId: transaction.id,
280вҶ’              billPaymentId: matchingBillPayment.id,
281вҶ’              fromBill: `${matchingBillPayment.billMonth}/${matchingBillPayment.billYear}`,
282вҶ’              interestRate: interest.rate,
283вҶ’              interestAmount: interest.amount,
284вҶ’            });
285вҶ’          }
286вҶ’        } catch (carryoverError) {
287вҶ’          // Log but don't fail the import if carryover linking fails
288вҶ’          console.error("Error linking carryover transaction:", carryoverError);
289вҶ’        }
290вҶ’      }
291вҶ’    }
292вҶ’
293вҶ’    // Build response message
294вҶ’    const messageParts = [`${created.length} transacoes importadas`];
295вҶ’    if (linkedCount > 0) {
296вҶ’      messageParts.push(`${linkedCount} vinculadas a recorrentes`);
297вҶ’    }
298вҶ’    if (carryoverLinkedCount > 0) {
299вҶ’      messageParts.push(`${carryoverLinkedCount} vinculadas a saldo rolado`);
300вҶ’    }
301вҶ’    const message =
302вҶ’      linkedCount > 0 || carryoverLinkedCount > 0
303вҶ’        ? `${messageParts[0]} (${messageParts.slice(1).join(", ")})`
304вҶ’        : `${created.length} transacoes importadas com sucesso`;
305вҶ’
306вҶ’    return NextResponse.json(
307вҶ’      {
308вҶ’        message,
309вҶ’        count: created.length,
310вҶ’        linkedCount,
311вҶ’        carryoverLinkedCount,
312вҶ’        linkedCarryovers,
313вҶ’        importBatchId,
314вҶ’      },
315вҶ’      { status: 201 }
316вҶ’    );
317вҶ’  } catch (error) {
318вҶ’    if (error instanceof Error && error.message === "Unauthorized") {
319вҶ’      return unauthorizedResponse();
320вҶ’    }
321вҶ’    console.error("Error importing transactions:", error);
322вҶ’    return NextResponse.json(
323вҶ’      { error: "Erro ao importar transacoes" },
324вҶ’      { status: 500 }
325вҶ’    );
326вҶ’  }
327вҶ’}
