import prisma from "@/lib/db"
import {
  sendMessage,
  answerCallbackQuery,
  editMessageText,
  getFile,
  downloadFile,
  type TelegramMessage,
  type TelegramCallbackQuery,
  type InlineKeyboardButton,
} from "./client"
import { parseExpenseMessage } from "./parser"
import { parseCSV } from "@/lib/csv-parser"
import { suggestCategory } from "@/lib/categorizer"
import { findDuplicate } from "@/lib/dedup"
import { formatCurrency } from "@/lib/utils"
import {
  handleSummaryQuery,
  handleCategoryQuery,
  handleTransactionsQuery,
} from "./queries"

export async function handleStartCommand(
  message: TelegramMessage,
  existingUserId: string | null
) {
  const chatId = message.chat.id
  const text = message.text || ""
  const token = text.replace("/start", "").trim()

  if (!token) {
    if (existingUserId) {
      return sendMessage(
        chatId,
        "Sua conta jГЎ estГЎ vinculada! Envie /menu para ver as opГ§Гөes."
      )
    }
    return sendMessage(
      chatId,
      "Bem-vindo ao MyPocket Bot!\n\nPara vincular sua conta, acesse ConfiguraГ§Гөes > Telegram no app e clique em \"Vincular Telegram\"."
    )
  }

  // Validate token
  const linkToken = await prisma.telegramLinkToken.findUnique({
    where: { token },
  })

  if (!linkToken) {
    return sendMessage(chatId, "Token invГЎlido. Gere um novo link nas configuraГ§Гөes do app.")
  }

  if (linkToken.expiresAt < new Date()) {
    await prisma.telegramLinkToken.delete({ where: { id: linkToken.id } })
    return sendMessage(chatId, "Token expirado. Gere um novo link nas configuraГ§Гөes do app.")
  }

  // Check if chatId already linked to another account
  const existingChatLink = await prisma.telegramLink.findUnique({
    where: { chatId: String(chatId) },
  })
  if (existingChatLink) {
    return sendMessage(
      chatId,
      "Este chat jГЎ estГЎ vinculado a outra conta. Desvincule primeiro com /desvincular."
    )
  }

  // Create link and delete token
  try {
    await prisma.$transaction([
      prisma.telegramLink.create({
        data: {
          userId: linkToken.userId,
          chatId: String(chatId),
        },
      }),
      prisma.telegramLinkToken.delete({ where: { id: linkToken.id } }),
    ])

    return sendMessage(
      chatId,
      "Conta vinculada com sucesso! \n\nEnvie /menu para ver as opГ§Гөes disponГӯveis."
    )
  } catch (error) {
    // Handle unique constraint violation (user already linked)
    return sendMessage(
      chatId,
      "Erro ao vincular conta. Sua conta pode jГЎ estar vinculada a outro chat."
    )
  }
}

export async function handleUnlinkCommand(
  chatId: number,
  userId: string
) {
  await prisma.telegramLink.deleteMany({
    where: { userId },
  })

  return sendMessage(
    chatId,
    "Conta desvinculada. Para vincular novamente, acesse ConfiguraГ§Гөes > Telegram no app."
  )
}

export async function handleMenuCommand(
  chatId: number,
  userId: string
) {
  return sendMessage(chatId, "рҹ“Ҡ MyPocket - Menu", {
    reply_markup: {
      inline_keyboard: [
        [{ text: "рҹ“Ҳ Resumo do mГӘs", callback_data: "summary:0" }],
        [{ text: "рҹҸ·пёҸ Gastos por categoria", callback_data: "categories:0" }],
        [{ text: "рҹ“Ӣ Гҡltimas transaГ§Гөes", callback_data: "txns:0" }],
      ],
    },
  })
}

export async function handleCallbackQuery(
  query: TelegramCallbackQuery,
  userId: string
) {
  const chatId = query.message?.chat.id
  const messageId = query.message?.message_id
  const data = query.data || ""

  if (!chatId || !messageId) return

  await answerCallbackQuery(query.id)

  if (data.startsWith("cancel:")) {
    return editMessageText(chatId, messageId, "OperaГ§ГЈo cancelada.")
  }

  if (data.startsWith("confirm:")) {
    const categoryIdFromData = data.replace("confirm:", "")
    return handleConfirmExpense(chatId, messageId, userId, query.message!, categoryIdFromData !== "none" ? categoryIdFromData : null)
  }

  if (data.startsWith("change_cat:")) {
    return handleShowCategories(chatId, messageId, userId, query.message)
  }

  if (data.startsWith("set_cat:")) {
    const categoryId = data.replace("set_cat:", "")
    return handleSetCategory(chatId, messageId, categoryId, query.message)
  }

  if (data.startsWith("csv_confirm:")) {
    const importKey = data.replace("csv_confirm:", "")
    return handleCsvConfirm(chatId, messageId, userId, importKey)
  }

  if (data.startsWith("csv_cancel:")) {
    return editMessageText(chatId, messageId, "ImportaГ§ГЈo cancelada.")
  }

  if (data.startsWith("summary:")) {
    return handleSummaryQuery(chatId, userId)
  }

  if (data.startsWith("categories:")) {
    return handleCategoryQuery(chatId, userId)
  }

  if (data.startsWith("txns:")) {
    const offset = parseInt(data.replace("txns:", "")) || 0
    return handleTransactionsQuery(chatId, userId, offset)
  }

  if (data.startsWith("menu:")) {
    return handleMenuCommand(chatId, userId)
  }
}

export async function handleExpenseMessage(
  message: TelegramMessage,
  userId: string
) {
  const chatId = message.chat.id
  const text = message.text || ""

  const parsed = parseExpenseMessage(text)
  if (!parsed) {
    return sendMessage(
      chatId,
      "NГЈo consegui entender. Envie no formato:\nDESCRICAO VALOR DD/MM/AAAA\n\nExemplo: PIX RESTAURANTE 45,90 05/03/2026"
    )
  }

  const { description, amount, date } = parsed

  // Auto-categorize
  const suggested = await suggestCategory(description, userId)
  const categoryName = suggested?.name || "Sem categoria"
  const categoryId = suggested?.id || null

  // Format date for display
  const dateStr = date.toLocaleDateString("pt-BR")

  const confirmData = `confirm:${categoryId || "none"}`
  const changeCatData = `change_cat:0`
  const cancelData = `cancel:0`

  return sendMessage(chatId, [
    "Nova despesa:",
    `рҹ“қ ${description}`,
    `рҹ’° ${formatCurrency(amount)}`,
    `рҹ“… ${dateStr}`,
    `рҹҸ·пёҸ ${categoryName}`,
  ].join("\n"), {
    reply_markup: {
      inline_keyboard: [
        [
          { text: "вң… Confirmar", callback_data: confirmData },
          { text: "вңҸпёҸ Categoria", callback_data: changeCatData },
          { text: "вқҢ Cancelar", callback_data: cancelData },
        ],
      ],
    },
  })
}

async function handleConfirmExpense(
  chatId: number,
  messageId: number,
  userId: string,
  message: TelegramMessage,
  overrideCategoryId: string | null = null
) {
  // Parse expense data from the confirmation message text
  const text = message.text || ""
  const lines = text.split("\n")

  const descLine = lines.find(l => l.startsWith("рҹ“қ"))
  const amountLine = lines.find(l => l.startsWith("рҹ’°"))
  const dateLine = lines.find(l => l.startsWith("рҹ“…"))
  const catLine = lines.find(l => l.startsWith("рҹҸ·пёҸ"))

  if (!descLine || !amountLine || !dateLine) {
    return editMessageText(chatId, messageId, "Erro: dados da transaГ§ГЈo nГЈo encontrados.")
  }

  const description = descLine.replace("рҹ“қ ", "")
  const amountStr = amountLine.replace("рҹ’° ", "").replace("R$", "").replace(/\./g, "").replace(",", ".").trim()
  const amount = parseFloat(amountStr)
  const dateParts = dateLine.replace("рҹ“… ", "").split("/")
  const date = new Date(
    parseInt(dateParts[2]),
    parseInt(dateParts[1]) - 1,
    parseInt(dateParts[0]),
    12, 0, 0
  )

  // Resolve category
  const categoryName = catLine?.replace("рҹҸ·пёҸ ", "") || "Sem categoria"
  let category = null
  if (overrideCategoryId) {
    category = await prisma.category.findUnique({ where: { id: overrideCategoryId } })
  } else if (categoryName !== "Sem categoria") {
    category = await prisma.category.findFirst({
      where: { name: categoryName, userId },
    })
  }

  // Check for duplicate
  const duplicate = await findDuplicate({
    userId,
    description,
    amount: -Math.abs(amount),
    date,
  })

  if (duplicate) {
    return editMessageText(
      chatId,
      messageId,
      `вҡ пёҸ TransaГ§ГЈo duplicata detectada!\n\nрҹ“қ ${description}\nрҹ’° ${formatCurrency(amount)}\nрҹ“… ${dateLine.replace("рҹ“… ", "")}\n\nEsta transaГ§ГЈo jГЎ existe no sistema.`
    )
  }

  // Create transaction
  await prisma.transaction.create({
    data: {
      userId,
      description,
      amount: -Math.abs(amount),
      date,
      type: "EXPENSE",
      origin: "Telegram",
      categoryId: category?.id || null,
      isFixed: false,
      isInstallment: false,
    },
  })

  const finalCategoryName = category?.name || categoryName

  return editMessageText(
    chatId,
    messageId,
    `вң… Despesa registrada!\n\nрҹ“қ ${description}\nрҹ’° ${formatCurrency(amount)}\nрҹ“… ${dateLine.replace("рҹ“… ", "")}\nрҹҸ·пёҸ ${finalCategoryName}`
  )
}

async function handleShowCategories(
  chatId: number,
  messageId: number,
  userId: string,
  currentMessage?: TelegramMessage
) {
  const categories = await prisma.category.findMany({
    where: { userId },
    orderBy: { name: "asc" },
  })

  if (categories.length === 0) {
    return editMessageText(chatId, messageId, "Nenhuma categoria cadastrada.")
  }

  // Preserve expense data lines for when a category is selected
  let expenseLines = ""
  const msgText = currentMessage?.text || ""
  const descLine = msgText.split("\n").find(l => l.startsWith("рҹ“қ"))
  const amountLine = msgText.split("\n").find(l => l.startsWith("рҹ’°"))
  const dateLine = msgText.split("\n").find(l => l.startsWith("рҹ“…"))

  if (descLine && amountLine && dateLine) {
    expenseLines = `\n${descLine}\n${amountLine}\n${dateLine}`
  }

  // Build keyboard with categories (max 2 per row)
  const keyboard: InlineKeyboardButton[][] = []
  for (let i = 0; i < categories.length; i += 2) {
    const row: InlineKeyboardButton[] = [
      { text: categories[i].name, callback_data: `set_cat:${categories[i].id}` },
    ]
    if (i + 1 < categories.length) {
      row.push({
        text: categories[i + 1].name,
        callback_data: `set_cat:${categories[i + 1].id}`,
      })
    }
    keyboard.push(row)
  }

  keyboard.push([{ text: "вқҢ Cancelar", callback_data: "cancel:0" }])

  return editMessageText(chatId, messageId, `Selecione a categoria:${expenseLines}`, {
    reply_markup: { inline_keyboard: keyboard },
  })
}

async function handleSetCategory(
  chatId: number,
  messageId: number,
  categoryId: string,
  currentMessage?: TelegramMessage
) {
  const category = await prisma.category.findUnique({
    where: { id: categoryId },
  })

  if (!category) {
    return editMessageText(chatId, messageId, "Categoria nГЈo encontrada.")
  }

  // Preserve original expense data lines from the message history
  let expenseLines = ""
  const msgText = currentMessage?.text || ""
  const descLine = msgText.split("\n").find(l => l.startsWith("рҹ“қ"))
  const amountLine = msgText.split("\n").find(l => l.startsWith("рҹ’°"))
  const dateLine = msgText.split("\n").find(l => l.startsWith("рҹ“…"))

  if (descLine && amountLine && dateLine) {
    expenseLines = `${descLine}\n${amountLine}\n${dateLine}\n`
  }

  const confirmData = `confirm:${categoryId}`
  const changeCatData = `change_cat:0`
  const cancelData = `cancel:0`

  return editMessageText(
    chatId,
    messageId,
    `Nova despesa:\n${expenseLines}рҹҸ·пёҸ ${category.name}`,
    {
      reply_markup: {
        inline_keyboard: [
          [
            { text: "вң… Confirmar", callback_data: confirmData },
            { text: "вңҸпёҸ Categoria", callback_data: changeCatData },
            { text: "вқҢ Cancelar", callback_data: cancelData },
          ],
        ],
      },
    }
  )
}

export async function handleDocumentMessage(
  message: TelegramMessage,
  userId: string
) {
  const chatId = message.chat.id
  const doc = message.document

  if (!doc) return

  // Check file extension
  const fileName = doc.file_name || ""
  if (!fileName.toLowerCase().endsWith(".csv")) {
    return sendMessage(chatId, "Apenas arquivos CSV sГЈo suportados.")
  }

  // Check file size (max 5MB to be safe)
  if (doc.file_size && doc.file_size > 5 * 1024 * 1024) {
    return sendMessage(chatId, "Arquivo muito grande. MГЎximo 5MB.")
  }

  try {
    // Download file
    const filePath = await getFile(doc.file_id)
    if (!filePath) {
      return sendMessage(chatId, "Erro ao acessar o arquivo.")
    }

    const content = await downloadFile(filePath)

    // Parse CSV
    const origin = "Telegram"
    const parsed = await parseCSV(content, origin)

    if (parsed.length === 0) {
      return sendMessage(chatId, "Nenhuma transaГ§ГЈo encontrada no arquivo.")
    }

    // Check for duplicates
    let duplicateCount = 0
    const uniqueTransactions: typeof parsed = []

    for (const t of parsed) {
      const amount = t.type === "EXPENSE" ? -Math.abs(t.amount) : Math.abs(t.amount)
      const dup = await findDuplicate({
        userId,
        description: t.description,
        amount,
        date: t.date,
      })
      if (dup) {
        duplicateCount++
      } else {
        uniqueTransactions.push(t)
      }
    }

    if (uniqueTransactions.length === 0) {
      return sendMessage(
        chatId,
        `Todas as ${parsed.length} transaГ§Гөes jГЎ existem no sistema.`
      )
    }

    // Store for confirmation in database
    // Clean expired entries first
    await prisma.telegramPendingImport.deleteMany({
      where: { expiresAt: { lt: new Date() } },
    })

    const pendingImport = await prisma.telegramPendingImport.create({
      data: {
        userId,
        chatId: String(chatId),
        payload: JSON.stringify(uniqueTransactions.map(t => ({
          description: t.description,
          amount: t.amount,
          date: t.date,
          categoryId: t.suggestedCategoryId || null,
          isInstallment: t.isInstallment || false,
          currentInstallment: t.currentInstallment || null,
          totalInstallments: t.totalInstallments || null,
          type: t.type || "EXPENSE",
        }))),
        origin,
        expiresAt: new Date(Date.now() + 10 * 60 * 1000),
      },
    })

    const summaryLines = [
      `рҹ“„ Arquivo: ${fileName}`,
      `рҹ“Ҡ ${parsed.length} transaГ§Гөes encontradas`,
    ]
    if (duplicateCount > 0) {
      summaryLines.push(`вҡ пёҸ ${duplicateCount} duplicatas ignoradas`)
    }
    summaryLines.push(`вң… ${uniqueTransactions.length} prontas para importar`)

    return sendMessage(chatId, summaryLines.join("\n"), {
      reply_markup: {
        inline_keyboard: [
          [
            { text: "вң… Importar", callback_data: `csv_confirm:${pendingImport.id}` },
            { text: "вқҢ Cancelar", callback_data: `csv_cancel:0` },
          ],
        ],
      },
    })
  } catch (error) {
    console.error("CSV import error:", error)
    return sendMessage(
      chatId,
      "Erro ao processar o arquivo. Verifique se Г© um CSV vГЎlido (C6, ItaГә ou BTG)."
    )
  }
}

export async function handleCsvConfirm(
  chatId: number,
  messageId: number,
  userId: string,
  importId: string
) {
  const pending = await prisma.telegramPendingImport.findUnique({
    where: { id: importId },
  })
  if (!pending || pending.expiresAt < new Date()) {
    if (pending) await prisma.telegramPendingImport.delete({ where: { id: importId } })
    return editMessageText(chatId, messageId, "ImportaГ§ГЈo expirada. Envie o arquivo novamente.")
  }

  await prisma.telegramPendingImport.delete({ where: { id: importId } })

  const transactions = JSON.parse(pending.payload) as Array<{
    description: string
    amount: number
    date: string | Date
    categoryId: string | null
    isInstallment: boolean
    currentInstallment: number | null
    totalInstallments: number | null
    type: string
  }>

  let importedCount = 0
  for (const t of transactions) {
    const type = t.type || "EXPENSE"
    let amount = t.amount
    if (type === "EXPENSE" && amount > 0) amount = -amount
    else if (type === "INCOME" && amount < 0) amount = Math.abs(amount)

    const dateStr = typeof t.date === "string" && !(t.date as string).includes("T")
      ? t.date + "T12:00:00"
      : t.date
    const transactionDate = new Date(dateStr)

    await prisma.transaction.create({
      data: {
        userId,
        description: t.description,
        amount,
        date: transactionDate,
        type,
        origin: pending!.origin,
        categoryId: t.categoryId,
        isFixed: false,
        isInstallment: t.isInstallment,
        currentInstallment: t.currentInstallment,
        totalInstallments: t.totalInstallments,
      },
    })
    importedCount++
  }

  return editMessageText(
    chatId,
    messageId,
    `вң… ${importedCount} transaГ§Гөes importadas com sucesso!`
  )
}

