import prisma from "@/lib/db"
import {
  sendMessage,
  answerCallbackQuery,
  editMessageText,
  getFile,
  downloadFile,
  type TelegramMessage,
  type TelegramCallbackQuery,
  type InlineKeyboardButton,
} from "./client"
import { parseExpenseMessage } from "./parser"
import { parseCSV } from "@/lib/csv-parser"
import { suggestCategory } from "@/lib/categorizer"
import { findDuplicate } from "@/lib/dedup"
import { formatCurrency } from "@/lib/utils"
import {
  handleSummaryQuery,
  handleCategoryQuery,
  handleTransactionsQuery,
} from "./queries"

export async function handleStartCommand(
  message: TelegramMessage,
  existingUserId: string | null
) {
  const chatId = message.chat.id
  const text = message.text || ""
  const token = text.replace("/start", "").trim()

  if (!token) {
    if (existingUserId) {
      return sendMessage(
        chatId,
        "Sua conta jГЎ estГЎ vinculada! Envie /menu para ver as opГ§Гөes."
      )
    }
    return sendMessage(
      chatId,
      "Bem-vindo ao MyPocket Bot!\n\nPara vincular sua conta, acesse ConfiguraГ§Гөes > Telegram no app e clique em \"Vincular Telegram\"."
    )
  }

  // Validate token
  const linkToken = await prisma.telegramLinkToken.findUnique({
    where: { token },
  })

  if (!linkToken) {
    return sendMessage(chatId, "Token invГЎlido. Gere um novo link nas configuraГ§Гөes do app.")
  }

  if (linkToken.expiresAt < new Date()) {
    await prisma.telegramLinkToken.delete({ where: { id: linkToken.id } })
    return sendMessage(chatId, "Token expirado. Gere um novo link nas configuraГ§Гөes do app.")
  }

  // Check if chatId already linked to another account
  const existingChatLink = await prisma.telegramLink.findUnique({
    where: { chatId: String(chatId) },
  })
  if (existingChatLink) {
    return sendMessage(
      chatId,
      "Este chat jГЎ estГЎ vinculado a outra conta. Desvincule primeiro com /desvincular."
    )
  }

  // Create link and delete token
  try {
    await prisma.$transaction([
      prisma.telegramLink.create({
        data: {
          userId: linkToken.userId,
          chatId: String(chatId),
        },
      }),
      prisma.telegramLinkToken.delete({ where: { id: linkToken.id } }),
    ])

    return sendMessage(
      chatId,
      "Conta vinculada com sucesso! \n\nEnvie /menu para ver as opГ§Гөes disponГӯveis."
    )
  } catch (error) {
    // Handle unique constraint violation (user already linked)
    return sendMessage(
      chatId,
      "Erro ao vincular conta. Sua conta pode jГЎ estar vinculada a outro chat."
    )
  }
}

export async function handleUnlinkCommand(
  chatId: number,
  userId: string
) {
  await prisma.telegramLink.deleteMany({
    where: { userId },
  })

  return sendMessage(
    chatId,
    "Conta desvinculada. Para vincular novamente, acesse ConfiguraГ§Гөes > Telegram no app."
  )
}

export async function handleMenuCommand(
  chatId: number,
  userId: string
) {
  return sendMessage(chatId, "рҹ“Ҡ MyPocket - Menu", {
    reply_markup: {
      inline_keyboard: [
        [{ text: "рҹ“Ҳ Resumo do mГӘs", callback_data: "summary:0" }],
        [{ text: "рҹҸ·пёҸ Gastos por categoria", callback_data: "categories:0" }],
        [{ text: "рҹ“Ӣ Гҡltimas transaГ§Гөes", callback_data: "txns:0" }],
      ],
    },
  })
}

export async function handleCallbackQuery(
  query: TelegramCallbackQuery,
  userId: string
) {
  const chatId = query.message?.chat.id
  const messageId = query.message?.message_id
  const data = query.data || ""

  if (!chatId || !messageId) return

  await answerCallbackQuery(query.id)

  if (data.startsWith("cancel:")) {
    return editMessageText(chatId, messageId, "OperaГ§ГЈo cancelada.")
  }

  if (data.startsWith("confirm:")) {
    const categoryIdFromData = data.replace("confirm:", "")
    return handleConfirmExpense(chatId, messageId, userId, query.message!, categoryIdFromData !== "none" ? categoryIdFromData : null)
  }

  if (data.startsWith("change_cat:")) {
    return handleShowCategories(chatId, messageId, userId, query.message)
  }

  if (data.startsWith("set_cat:")) {
    const categoryId = data.replace("set_cat:", "")
    return handleSetCategory(chatId, messageId, categoryId, query.message)
  }

  if (data.startsWith("csv_confirm:")) {
    const importKey = data.replace("csv_confirm:", "")
    return handleCsvConfirm(chatId, messageId, userId, importKey)
  }

  if (data.startsWith("csv_cancel:")) {
    return editMessageText(chatId, messageId, "ImportaГ§ГЈo cancelada.")
  }

  if (data.startsWith("summary:")) {
    return handleSummaryQuery(chatId, userId)
  }

  if (data.startsWith("categories:")) {
    return handleCategoryQuery(chatId, userId)
  }

  if (data.startsWith("txns:")) {
    const offset = parseInt(data.replace("txns:", "")) || 0
    return handleTransactionsQuery(chatId, userId, offset)
  }

  if (data.startsWith("menu:")) {
    return handleMenuCommand(chatId, userId)
  }
}

export async function handleExpenseMessage(
  message: TelegramMessage,
  userId: string
) {
  const chatId = message.chat.id
  const text = message.text || ""

  const parsed = parseExpenseMessage(text)
  if (!parsed) {
    return sendMessage(
      chatId,
