            { text: "вқҢ Cancelar", callback_data: cancelData },
          ],
        ],
      },
    }
  )
}

export async function handleDocumentMessage(
  message: TelegramMessage,
  userId: string
) {
  const chatId = message.chat.id
  const doc = message.document

  if (!doc) return

  // Check file extension
  const fileName = doc.file_name || ""
  if (!fileName.toLowerCase().endsWith(".csv")) {
    return sendMessage(chatId, "Apenas arquivos CSV sГЈo suportados.")
  }

  // Check file size (max 5MB to be safe)
  if (doc.file_size && doc.file_size > 5 * 1024 * 1024) {
    return sendMessage(chatId, "Arquivo muito grande. MГЎximo 5MB.")
  }

  try {
    // Download file
    const filePath = await getFile(doc.file_id)
    if (!filePath) {
      return sendMessage(chatId, "Erro ao acessar o arquivo.")
    }

    const content = await downloadFile(filePath)

    // Parse CSV
    const origin = "Telegram"
    const parsed = await parseCSV(content, origin)

    if (parsed.length === 0) {
      return sendMessage(chatId, "Nenhuma transaГ§ГЈo encontrada no arquivo.")
    }

    // Check for duplicates
    let duplicateCount = 0
    const uniqueTransactions: typeof parsed = []

    for (const t of parsed) {
      const amount = t.type === "EXPENSE" ? -Math.abs(t.amount) : Math.abs(t.amount)
      const dup = await findDuplicate({
        userId,
        description: t.description,
        amount,
        date: t.date,
      })
      if (dup) {
        duplicateCount++
      } else {
        uniqueTransactions.push(t)
      }
    }

    if (uniqueTransactions.length === 0) {
      return sendMessage(
        chatId,
        `Todas as ${parsed.length} transaГ§Гөes jГЎ existem no sistema.`
      )
    }

    // Store for confirmation in database
    // Clean expired entries first
    await prisma.telegramPendingImport.deleteMany({
      where: { expiresAt: { lt: new Date() } },
    })

    const pendingImport = await prisma.telegramPendingImport.create({
      data: {
        userId,
        chatId: String(chatId),
        payload: JSON.stringify(uniqueTransactions.map(t => ({
          description: t.description,
          amount: t.amount,
          date: t.date,
          categoryId: t.suggestedCategoryId || null,
          isInstallment: t.isInstallment || false,
          currentInstallment: t.currentInstallment || null,
          totalInstallments: t.totalInstallments || null,
          type: t.type || "EXPENSE",
        }))),
        origin,
        expiresAt: new Date(Date.now() + 10 * 60 * 1000),
      },
    })

    const summaryLines = [
      `рҹ“„ Arquivo: ${fileName}`,
      `рҹ“Ҡ ${parsed.length} transaГ§Гөes encontradas`,
    ]
    if (duplicateCount > 0) {
      summaryLines.push(`вҡ пёҸ ${duplicateCount} duplicatas ignoradas`)
    }
    summaryLines.push(`вң… ${uniqueTransactions.length} prontas para importar`)

    return sendMessage(chatId, summaryLines.join("\n"), {
      reply_markup: {
        inline_keyboard: [
          [
            { text: "вң… Importar", callback_data: `csv_confirm:${pendingImport.id}` },
            { text: "вқҢ Cancelar", callback_data: `csv_cancel:0` },
          ],
        ],
      },
    })
  } catch (error) {
    console.error("CSV import error:", error)
    return sendMessage(
      chatId,
      "Erro ao processar o arquivo. Verifique se Г© um CSV vГЎlido (C6, ItaГә ou BTG)."
    )
  }
}

export async function handleCsvConfirm(
  chatId: number,
  messageId: number,
  userId: string,
  importId: string
) {
  const pending = await prisma.telegramPendingImport.findUnique({
    where: { id: importId },
  })
  if (!pending || pending.expiresAt < new Date()) {
    if (pending) await prisma.telegramPendingImport.delete({ where: { id: importId } })
    return editMessageText(chatId, messageId, "ImportaГ§ГЈo expirada. Envie o arquivo novamente.")
  }

  // Validate that the pending import belongs to the requesting user
  if (pending.userId !== userId) {
    return editMessageText(chatId, messageId, "Erro: importaГ§ГЈo nГЈo encontrada.")
  }

  await prisma.telegramPendingImport.delete({ where: { id: importId } })

  const transactions = JSON.parse(pending.payload) as Array<{
    description: string
    amount: number
    date: string | Date
    categoryId: string | null
    isInstallment: boolean
    currentInstallment: number | null
    totalInstallments: number | null
    type: string
  }>

  const importBatchId = crypto.randomUUID()
  let importedCount = 0
  for (const t of transactions) {
    const type = t.type || "EXPENSE"
    let amount = t.amount
    if (type === "EXPENSE" && amount > 0) amount = -amount
    else if (type === "INCOME" && amount < 0) amount = Math.abs(amount)

    const dateStr = typeof t.date === "string" && !(t.date as string).includes("T")
      ? t.date + "T12:00:00"
      : t.date
    const transactionDate = new Date(dateStr)

    await prisma.transaction.create({
      data: {
        userId,
        description: t.description,
        amount,
        date: transactionDate,
        type,
        origin: pending.origin,
        categoryId: t.categoryId,
        isFixed: false,
        isInstallment: t.isInstallment,
        currentInstallment: t.currentInstallment,
        totalInstallments: t.totalInstallments,
        importBatchId,
      },
    })
    importedCount++
  }

  return editMessageText(
    chatId,
    messageId,
    `вң… ${importedCount} transaГ§Гөes importadas com sucesso!`
  )
}

