    date: string | Date
    categoryId: string | null
    isInstallment: boolean
    currentInstallment: number | null
    totalInstallments: number | null
    type: string
  }>

  const importBatchId = crypto.randomUUID()
  let importedCount = 0
  for (const t of transactions) {
    const type = t.type || "EXPENSE"
    let amount = t.amount
    if (type === "EXPENSE" && amount > 0) amount = -amount
    else if (type === "INCOME" && amount < 0) amount = Math.abs(amount)

    const dateStr = typeof t.date === "string" && !(t.date as string).includes("T")
      ? t.date + "T12:00:00"
      : t.date
    const transactionDate = new Date(dateStr)

    await prisma.transaction.create({
      data: {
        userId,
        description: t.description,
        amount,
        date: transactionDate,
        type,
        origin: pending.origin,
        categoryId: t.categoryId,
        isFixed: false,
        isInstallment: t.isInstallment,
        currentInstallment: t.currentInstallment,
        totalInstallments: t.totalInstallments,
        importBatchId,
      },
    })
    importedCount++
  }

  return editMessageText(
    chatId,
    messageId,
    `вң… ${importedCount} transaГ§Гөes importadas com sucesso!`
  )
}

