    let amount = t.amount
    if (type === "EXPENSE" && amount > 0) amount = -amount
    else if (type === "INCOME" && amount < 0) amount = Math.abs(amount)

    const dateStr = typeof t.date === "string" && !(t.date as string).includes("T")
      ? t.date + "T12:00:00"
