  );

  const created: ImportResult["created"] = [];
  let linkedCount = 0;
  let skippedCount = 0;
  let carryoverLinkedCount = 0;
  const linkedCarryovers: ImportResult["linkedCarryovers"] = [];

  for (const t of transactions) {
    const type = t.type || "EXPENSE";
    let amount = t.amount;

    if (type === "EXPENSE" && amount > 0) {
      amount = -amount;
    } else if (type === "INCOME" && amount < 0) {
      amount = Math.abs(amount);
    }

    // Parse date safely to avoid timezone issues with YYYY-MM-DD format
    const dateValue = typeof t.date === "string" && !t.date.includes("T")
