      }
    } else {
      linkedCount++;
    }

    // Check for duplicate transaction
    const duplicate = await findDuplicate({
      userId,
      description: t.description,
      amount,
      date: transactionDate,
    });
    if (duplicate) {
      skippedCount++;
      continue;
    }

